import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Typography,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Chip,
  Skeleton,
  Button,
  useTheme,
  useMediaQuery,
  Fade,
  Pagination
} from '@mui/material';
import {
  History,
  Refresh
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';
import { applyTradeFilters } from '../../utils/tradeFilters';

const ClosedOperationsTable = ({ hideValues = false }) => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));

  const [trades, setTrades] = useState([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [page, setPage] = useState(1);
  const tradesPerPage = 10;

  // Função para formatar moeda
  const formatCurrency = (value) => {
    if (hideValues) return '***';
    if (value === null || value === undefined || isNaN(value)) return '$0.00';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }).format(value);
  };

  // Função para formatar porcentagem
  const formatPercentage = (value) => {
    if (hideValues) return '***';
    if (value === null || value === undefined || isNaN(value)) return '0.00%';
    return `${value.toFixed(2)}%`;
  };

  // Função para formatar data/hora
  const formatDateTime = (dateString) => {
    if (!dateString) return '-';
    try {
      const date = new Date(dateString);
      return date.toLocaleString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch (error) {
      return '-';
    }
  };

  // Componente para exibir o lado da operação
  const SideChip = ({ side }) => {
    const isLong = side?.toLowerCase() === 'long';
    return (
      <Chip
        label={side?.toUpperCase() || 'N/A'}
        size="small"
        sx={{
          bgcolor: isLong ? 'success.main' : 'error.main',
          color: 'white',
          fontWeight: 'bold',
          fontSize: '0.75rem'
        }}
      />
    );
  };

  // Função para carregar trades
  const loadTrades = useCallback(async (isRefresh = false) => {
    try {
      if (isRefresh) {
        setRefreshing(true);
      } else {
        setLoading(true);
      }

      const response = await dashboardService.getClosedTrades();
      console.log('🔍 ClosedOperationsTable: Resposta recebida:', response);

      if (response?.trades) {
        console.log('📊 ClosedOperationsTable: Trades encontrados:', response.trades.length);
        // Aplicar filtro básico para mostrar apenas operações válidas
        const filters = {
          fullyRealized: false, // Mostrar todas as operações
          period: 'all',
          symbol: '',
          side: 'all',
          result: 'all'
        };

        const filteredTrades = applyTradeFilters(response.trades, filters);
        console.log('✅ ClosedOperationsTable: Trades filtrados:', filteredTrades.length);
        setTrades(filteredTrades);
      } else {
        console.warn('⚠️ ClosedOperationsTable: Nenhum trade encontrado na resposta');
        setTrades([]);
      }
    } catch (error) {
      console.error('Erro ao carregar trades:', error);
      setTrades([]);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  // Carregar trades na inicialização
  useEffect(() => {
    loadTrades();
  }, [loadTrades]);

  // Calcular trades para a página atual
  const startIndex = (page - 1) * tradesPerPage;
  const endIndex = startIndex + tradesPerPage;
  const currentTrades = trades.slice(startIndex, endIndex);
  const totalPages = Math.ceil(trades.length / tradesPerPage);

  // Componente de loading skeleton
  const LoadingSkeleton = () => (
    <Box sx={{ p: 2 }}>
      {[...Array(5)].map((_, index) => (
        <Skeleton key={index} variant="rectangular" height={60} sx={{ mb: 1 }} />
      ))}
    </Box>
  );

  // Renderizar conteúdo principal
  const renderContent = () => {
    if (loading) {
      return <LoadingSkeleton />;
    }

    if (trades.length === 0) {
      return (
        <Box sx={{ 
          display: 'flex', 
          flexDirection: 'column',
          alignItems: 'center', 
          justifyContent: 'center', 
          p: 6,
          minHeight: 300
        }}>
          <History sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
          <Typography variant="h6" color="text.secondary" gutterBottom>
            Nenhuma operação encerrada
          </Typography>
          <Typography variant="body2" color="text.secondary" textAlign="center">
            As operações encerradas aparecerão aqui automaticamente.
            <br />
            Certifique-se de que suas credenciais da API estão configuradas corretamente.
          </Typography>
          <Button 
            variant="outlined" 
            onClick={() => loadTrades()} 
            sx={{ mt: 2 }}
            startIcon={<Refresh />}
          >
            Tentar Novamente
          </Button>
        </Box>
      );
    }

    return (
      <Fade in={true} timeout={500}>
        <Box>
          <TableContainer 
            component={Paper} 
            sx={{ 
              maxHeight: isMobile ? '400px' : '500px',
              position: 'relative',
              '& .MuiTableCell-head': {
                backgroundColor: theme.palette.grey[50],
                fontWeight: 'bold'
              }
            }}
          >
            {refreshing && (
              <Box sx={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                height: 3,
                bgcolor: 'primary.main',
                animation: 'pulse 1.5s ease-in-out infinite',
                '@keyframes pulse': {
                  '0%': { opacity: 0.4 },
                  '50%': { opacity: 1 },
                  '100%': { opacity: 0.4 }
                },
                zIndex: 10
              }} />
            )}

            <Table stickyHeader size={isMobile ? 'small' : 'medium'}>
              <TableHead>
                <TableRow>
                  <TableCell>Par</TableCell>
                  <TableCell>Lado</TableCell>
                  <TableCell align="right">Tamanho</TableCell>
                  <TableCell align="right">Entrada</TableCell>
                  <TableCell align="right">Saída</TableCell>
                  <TableCell align="right">PnL</TableCell>
                  <TableCell align="right">ROE</TableCell>
                  <TableCell>Data/Hora</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {currentTrades.map((trade, index) => (
                  <TableRow 
                    key={trade.id || `trade_${index}_${trade.symbol}_${trade.closed_at}`} 
                    hover 
                    sx={{ 
                      '&:nth-of-type(odd)': { 
                        backgroundColor: theme.palette.action.hover 
                      }
                    }}
                  >
                    <TableCell>
                      <Typography variant="body2" sx={{ fontWeight: 'bold' }}>
                        {trade.symbol || '-'}
                      </Typography>
                      <Typography variant="caption" color="text.secondary">
                        {trade.leverage ? `${trade.leverage}x` : '50x'}
                      </Typography>
                    </TableCell>

                    <TableCell>
                      <SideChip side={trade.side} />
                    </TableCell>

                    <TableCell align="right">
                      <Typography variant="body2">
                        {trade.size > 0 ? trade.size.toFixed(4) : '-'}
                      </Typography>
                    </TableCell>

                    <TableCell align="right">
                      <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
                        {formatCurrency(trade.entry_price)}
                      </Typography>
                    </TableCell>

                    <TableCell align="right">
                      <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
                        {trade.exit_price !== null && trade.exit_price !== undefined ? formatCurrency(trade.exit_price) : '-'}
                      </Typography>
                    </TableCell>

                    <TableCell align="right">
                      <Typography
                        variant="body2"
                        sx={{
                          color: trade.pnl >= 0 ? 'success.main' : 'error.main',
                          fontWeight: 'bold'
                        }}
                      >
                        {formatCurrency(trade.pnl)}
                      </Typography>
                    </TableCell>

                    <TableCell align="right">
                      <Typography
                        variant="body2"
                        sx={{
                          color: trade.roe >= 0 ? 'success.main' : 'error.main',
                          fontWeight: 'bold'
                        }}
                      >
                        {formatPercentage(trade.roe)}
                      </Typography>
                    </TableCell>

                    <TableCell>
                      <Typography variant="body2" color="text.secondary">
                        {formatDateTime(trade.closed_at)}
                      </Typography>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>

          {/* Paginação */}
          {totalPages > 1 && (
            <Box sx={{ display: 'flex', justifyContent: 'center', mt: 2 }}>
              <Pagination 
                count={totalPages}
                page={page}
                onChange={(event, newPage) => setPage(newPage)}
                color="primary"
                size={isMobile ? 'small' : 'medium'}
              />
            </Box>
          )}
        </Box>
      </Fade>
    );
  };

  return (
    <Box sx={{ 
      p: 3, 
      bgcolor: 'background.paper', 
      borderRadius: 2, 
      boxShadow: 1,
      border: `1px solid ${theme.palette.divider}`
    }}>
      <Box sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        mb: 2
      }}>
        <Typography variant="h6" sx={{ fontWeight: 'bold' }}>
          📈 Operações Encerradas ({trades.length})
        </Typography>
        <Button 
          variant="outlined" 
          size="small"
          onClick={() => loadTrades(true)}
          startIcon={<Refresh />}
          disabled={refreshing}
          sx={{ 
            borderRadius: 2,
            textTransform: 'none'
          }}
        >
          {refreshing ? 'Atualizando...' : 'Atualizar'}
        </Button>
      </Box>

      {renderContent()}
    </Box>
  );
};

export default ClosedOperationsTable;
